187→          <div className="flex flex-1 flex-col overflow-hidden">
188→            {/* Inner tabs */}
189→            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
190→              {(["checkpoints", "transcript", "trails", "diff"] as const).map((tab) => (
191→                <button
192→                  key={tab}
193→                  onClick={() => setInnerTab(tab)}
194→                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
195→                    innerTab === tab
196→                      ? "border-accent text-fg"
197→                      : "border-transparent text-fg-subtle hover:text-fg-muted"
198→                  }`}
199→                >
200→                  {tab === "checkpoints"
201→                    ? "Checkpoints"
202→                    : tab === "transcript"
203→                      ? "Transcript"
204→                      : tab === "trails"
205→                        ? "Trails"
206→                        : "Diff"}
207→                </button>
208→              ))}
209→            </div>
210→
211→            {/* Main view */}
212→            <div className="flex-1 overflow-y-auto bg-bg">
213→              {innerTab === "checkpoints" && (
214→                <CheckpointList
215→                  repoPath={activeTab.repoPath}
216→                  branch={activeTab.branch}
217→                  onSelectCheckpoint={(cp) => {
218→                    setSelectedCheckpoint(cp);
