import { useState, useMemo } from "react";
import { Loader2, User, Bot, Wrench, ChevronDown, ChevronRight } from "lucide-react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { useTranscriptQuery } from "../../hooks/use-tauri-query";
import type { CheckpointSummary } from "../../lib/ipc";

interface TranscriptViewProps {
  repoPath: string;
  checkpoint: CheckpointSummary | null;
}

function tryFormatJson(text: string): { formatted: string; isJson: boolean } {
  const trimmed = text.trim();
  if (
    (trimmed.startsWith("{") && trimmed.endsWith("}")) ||
    (trimmed.startsWith("[") && trimmed.endsWith("]"))
  ) {
    try {
      const parsed = JSON.parse(trimmed);
      return { formatted: JSON.stringify(parsed, null, 2), isJson: true };
    } catch {
      // not valid JSON
    }
  }
  return { formatted: text, isJson: false };
}

function JsonViewer({ text }: { text: string }) {
  const [collapsed, setCollapsed] = useState(text.length > 500);
  const formatted = useMemo(() => {
    try {
      return JSON.stringify(JSON.parse(text.trim()), null, 2);
    } catch {
      return text;
    }
  }, [text]);

  const lines = formatted.split("\n");
  const preview = lines.slice(0, 6).join("\n");

  return (
    <div className="relative">
      <pre className="overflow-x-auto whitespace-pre-wrap font-mono text-xs leading-relaxed">
        {collapsed ? (
          <>
            <span className="text-fg-subtle">{preview}</span>
            {lines.length > 6 && (
              <span className="text-fg-faint">{"\n  ..."}</span>
            )}
          </>
        ) : (
          <JsonHighlight json={formatted} />
        )}
      </pre>
      {lines.length > 6 && (
        <button
          onClick={() => setCollapsed(!collapsed)}
          className="mt-1 flex items-center gap-1 text-[10px] text-accent-fg hover:text-accent"
        >
          {collapsed ? <ChevronRight size={10} /> : <ChevronDown size={10} />}
          {collapsed ? `Show all (${lines.length} lines)` : "Collapse"}
        </button>
      )}
    </div>
  );
}

function JsonHighlight({ json }: { json: string }) {
  // Simple JSON syntax coloring via regex
  const colored = json.replace(
    /("(?:\\.|[^"\\])*")\s*:|("(?:\\.|[^"\\])*")|(true|false|null)|(-?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)/g,
    (match, key, str, bool, num) => {
      if (key) return `<k>${key}</k>:`;
      if (str) return `<s>${str}</s>`;
      if (bool) return `<b>${bool}</b>`;
      if (num) return `<n>${num}</n>`;
      return match;
    }
  );

  return (
    <span
      dangerouslySetInnerHTML={{ __html: colored }}
      className="json-highlight"
    />
  );
}

function MarkdownContent({ content }: { content: string }) {
  return (
    <div className="prose-transcript">
      <ReactMarkdown remarkPlugins={[remarkGfm]}>{content}</ReactMarkdown>
    </div>
  );
}

function MessageContent({ content, toolInput }: { content: string; toolInput: string | null }) {
  if (toolInput) {
    const { isJson } = tryFormatJson(toolInput);
    if (isJson) {
      return <JsonViewer text={toolInput} />;
    }
    return (
      <pre className="overflow-x-auto whitespace-pre-wrap font-mono text-xs text-fg-subtle">
        {toolInput}
      </pre>
    );
  }

  // Check if content looks like JSON
  const { isJson } = tryFormatJson(content);
  if (isJson) {
    return <JsonViewer text={content} />;
  }

  return <MarkdownContent content={content} />;
}

