  1→import { useState, useCallback } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import { XTerminal } from "./XTerminal";
  4→import type { Tab } from "../../App";
  5→
  6→interface TerminalPanelProps {
  7→  height: number;
  8→  tab: Tab;
  9→  onToggle: () => void;
 10→}
 11→
 12→interface TermSession {
 13→  id: string;
 14→  agent: string;
 15→  label: string;
 16→}
 17→
 18→export function TerminalPanel({ height, tab, onToggle }: TerminalPanelProps) {
 19→  const [sessions, setSessions] = useState<TermSession[]>([]);
 20→  const [activeSessionIdx, setActiveSessionIdx] = useState(0);
 21→
 22→  const activeSession = sessions[activeSessionIdx] ?? null;
 23→
 24→  const launchAgent = useCallback(
 25→    async (agent: string) => {
 26→      if (!tab.repoPath) {
 27→        console.warn("No repo path set — cannot launch agent");
 28→        return;
 29→      }
 30→      try {
 31→        const sessionId: string = await invoke("spawn_agent", {
 32→          repoPath: tab.repoPath,
 33→          agent,
 34→        });
 35→        const newSession: TermSession = {
 36→          id: sessionId,
 37→          agent,
 38→          label: `${agent === "claude-code" ? "Claude Code" : "Codex"} — ${tab.branch}`,
 39→        };
 40→        setSessions((prev) => [...prev, newSession]);
 41→        setActiveSessionIdx(sessions.length);
 42→      } catch (err) {
 43→        console.error("Failed to spawn agent:", err);
 44→      }
 45→    },
 46→    [tab.repoPath, tab.branch, sessions.length]
 47→  );
 48→
 49→  return (
 50→    <div className="flex shrink-0 flex-col bg-[#0a0a0a]" style={{ height }}>
 51→      {/* Terminal header with session tabs */}
 52→      <div className="flex items-center gap-2 border-t border-border bg-bg-raised px-3 py-1.5">
 53→        {sessions.map((session, idx) => (
 54→          <button
 55→            key={session.id}
 56→            onClick={() => setActiveSessionIdx(idx)}
 57→            className={`flex items-center gap-1.5 rounded-md px-2.5 py-1 text-[11px] ${
 58→              idx === activeSessionIdx
 59→                ? "bg-accent-bg text-accent-fg"
 60→                : "text-fg-subtle hover:bg-bg-hover"
 61→            }`}
 62→          >
 63→            <span className="h-1.5 w-1.5 animate-pulse rounded-full bg-green" />
 64→            {session.label}
 65→          </button>
 66→        ))}
 67→
 68→        {sessions.length === 0 && (
 69→          <>
 70→            <button
 71→              onClick={() => launchAgent("claude-code")}
 72→              className="flex items-center gap-1.5 rounded-md border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-accent-fg"
 73→            >
 74→              + Claude Code
 75→            </button>
 76→            <button
 77→              onClick={() => launchAgent("codex")}
 78→              className="flex items-center gap-1.5 rounded-md border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-green hover:text-green"
 79→            >
 80→              + Codex
 81→            </button>
 82→          </>
 83→        )}
 84→
 85→        {sessions.length > 0 && (
 86→          <button
 87→            onClick={() => {
 88→              // Quick launch menu — cycle agents
 89→              const nextAgent =
 90→                sessions[sessions.length - 1]?.agent === "claude-code"
 91→                  ? "codex"
 92→                  : "claude-code";
 93→              launchAgent(nextAgent);
 94→            }}
 95→            className="rounded-md px-2 py-1 text-[11px] text-fg-subtle hover:bg-bg-hover"
 96→          >
 97→            +
 98→          </button>
 99→        )}
100→
101→        <button
102→          onClick={onToggle}
103→          className="ml-auto px-2 py-1 text-[11px] text-fg-subtle hover:text-fg-muted"
104→        >
105→          ⌃` Toggle ▾
106→        </button>
107→      </div>
108→
109→      {/* Terminal body */}
