  9→use std::collections::HashSet;
 10→use std::sync::Mutex;
 11→use tauri::{Emitter, State};
 12→
 13→struct AppState {
 14→    pty_manager: pty::PtyManager,
 15→    watched_repos: HashSet<String>,
 16→}
 17→
 18→#[tauri::command]
 19→fn list_repos() -> Result<Vec<git::RepoInfo>, String> {
 20→    let repo_paths = config::discover_repos();
 21→    let mut repos = Vec::new();
 22→    for path in repo_paths {
 23→        match git::get_repo_info(&path) {
 24→            Ok(info) => repos.push(info),
 25→            Err(e) => eprintln!("Skipping repo {}: {}", path, e),
 26→        }
 27→    }
 28→    Ok(repos)
 29→}
 30→
 31→#[tauri::command]
 32→fn list_checkpoints(
 33→    repo_path: String,
 34→    branch: String,
 35→) -> Result<Vec<checkpoint::CheckpointSummary>, String> {
 36→    let repo = git::open_repo(&repo_path)?;
 37→    checkpoint::list_checkpoints(&repo, &branch)
 38→}
 39→
 40→#[tauri::command]
 41→fn get_transcript(
 42→    repo_path: String,
 43→    checkpoint_id: String,
 44→    session_index: u32,
 45→) -> Result<Vec<session::TranscriptMessage>, String> {
 46→    let repo = git::open_repo(&repo_path)?;
 47→
 48→    let prefix = &checkpoint_id[..2];
 49→    let suffix = &checkpoint_id[2..];
 50→    let session_dir = format!("{}/{}/{}", prefix, suffix, session_index);
 51→
 52→    // Read the checkpoint metadata to find the actual transcript path
 53→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
 54→    let transcript_path = read_blob(&repo, &meta_path)
 55→        .ok()
 56→        .and_then(|meta_content| {
 57→            let meta: serde_json::Value = serde_json::from_str(&meta_content).ok()?;
 58→            let sessions = meta.get("sessions")?.as_array()?;
 59→            let session = sessions.get(session_index as usize)?;
 60→            session.get("transcript")?.as_str().map(|s| s.to_string())
 61→        });
 62→
 63→    // Build candidates: metadata path (may be absolute from tree root), then fallbacks
 64→    let mut candidates = Vec::new();
 65→    if let Some(ref path) = transcript_path {
 66→        // Paths from metadata may be absolute (leading /) — strip it for tree lookup
 67→        candidates.push(path.trim_start_matches('/').to_string());
 68→    }
 69→    candidates.push(format!("{}/full.jsonl", session_dir));
 70→    candidates.push(format!("{}/transcript.jsonl", session_dir));
 71→
 72→    for path in &candidates {
 73→        if let Ok(content) = read_blob(&repo, path) {
 74→            return Ok(session::read_transcript(&content));
 75→        }
 76→    }
 77→
 78→    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
 79→}
