168→#[derive(serde::Serialize)]
169→struct FileDiff {
170→    path: String,
171→    status: String, // "added", "modified", "deleted"
172→    hunks: Vec<DiffHunk>,
173→}
174→
175→#[derive(serde::Serialize)]
176→struct DiffHunk {
177→    header: String,
178→    lines: Vec<DiffLine>,
179→}
180→
181→#[derive(serde::Serialize)]
182→struct DiffLine {
183→    kind: String, // "add", "delete", "context"
184→    content: String,
185→    old_lineno: Option<u32>,
186→    new_lineno: Option<u32>,
187→}
188→
189→/// Convert a git2::Diff into our FileDiff structs
190→fn collect_diff_files(diff: &git2::Diff) -> Result<Vec<FileDiff>, String> {
191→    let mut files: Vec<FileDiff> = Vec::new();
192→
193→    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
194→        let path = delta
195→            .new_file()
196→            .path()
197→            .or_else(|| delta.old_file().path())
198→            .map(|p| p.to_string_lossy().to_string())
199→            .unwrap_or_default();
200→
201→        let status = match delta.status() {
202→            git2::Delta::Added => "added",
203→            git2::Delta::Deleted => "deleted",
204→            _ => "modified",
205→        };
206→
207→        // Ensure we have a FileDiff entry for this path
208→        if files.last().map_or(true, |f| f.path != path) {
209→            files.push(FileDiff {
210→                path: path.clone(),
211→                status: status.to_string(),
212→                hunks: Vec::new(),
213→            });
214→        }
215→
216→        let file = files.last_mut().unwrap();
217→
218→        // New hunk
219→        if let Some(h) = hunk {
220→            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
221→            if file.hunks.last().map_or(true, |last| last.header != header) {
222→                file.hunks.push(DiffHunk {
223→                    header,
224→                    lines: Vec::new(),
225→                });
226→            }
227→        }
228→
229→        // Diff line
230→        if let Some(current_hunk) = file.hunks.last_mut() {
231→            let kind = match line.origin() {
232→                '+' => "add",
233→                '-' => "delete",
234→                ' ' => "context",
235→                _ => return true,
236→            };
237→            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
238→            current_hunk.lines.push(DiffLine {
239→                kind: kind.to_string(),
240→                content,
241→                old_lineno: line.old_lineno(),
242→                new_lineno: line.new_lineno(),
243→            });
244→        }
245→
246→        true
247→    })
248→    .map_err(|e| format!("Failed to print diff: {}", e))?;
249→
250→    Ok(files)
251→}
252→
253→#[tauri::command]
254→fn get_checkpoint_diff(
255→    repo_path: String,
256→    commit_sha: String,
257→) -> Result<Vec<FileDiff>, String> {
258→    if commit_sha.is_empty() {
259→        return Err("No commit SHA available for this checkpoint".to_string());
260→    }
261→
262→    let repo = git::open_repo(&repo_path)?;
263→    let oid = git2::Oid::from_str(&commit_sha)
264→        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
265→    let commit = repo
266→        .find_commit(oid)
267→        .map_err(|e| format!("Commit not found: {}", e))?;
268→
269→    let tree = commit
270→        .tree()
271→        .map_err(|e| format!("Failed to get tree: {}", e))?;
272→
273→    // Diff against parent (or empty tree if no parent)
274→    let parent_tree = commit
275→        .parent(0)
276→        .ok()
277→        .and_then(|p| p.tree().ok());
278→
279→    let diff = repo
280→        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
281→        .map_err(|e| format!("Failed to compute diff: {}", e))?;
282→
283→    collect_diff_files(&diff)
284→}
285→
286→#[tauri::command]
287→fn get_branch_diff(
288→    repo_path: String,
289→    branch: String,
290→) -> Result<Vec<FileDiff>, String> {
291→    let repo = git::open_repo(&repo_path)?;
292→
293→    // Resolve the branch HEAD
294→    let branch_ref = repo
295→        .find_branch(&branch, git2::BranchType::Local)
296→        .map_err(|e| format!("Branch not found: {}", e))?;
297→    let branch_commit = branch_ref
298→        .get()
299→        .peel_to_commit()
300→        .map_err(|e| format!("Failed to resolve branch HEAD: {}", e))?;
301→
302→    // Find the default branch (try main, then master)
303→    let default_branch_name = if repo.find_branch("main", git2::BranchType::Local).is_ok() {
304→        "main"
305→    } else if repo.find_branch("master", git2::BranchType::Local).is_ok() {
306→        "master"
307→    } else {
308→        return Err("No default branch (main/master) found".to_string());
309→    };
310→
311→    // If we're diffing the default branch against itself, return empty
312→    if branch == default_branch_name {
313→        return Ok(Vec::new());
314→    }
315→
316→    let default_ref = repo
317→        .find_branch(default_branch_name, git2::BranchType::Local)
318→        .map_err(|e| format!("Default branch error: {}", e))?;
319→    let default_commit = default_ref
320→        .get()
321→        .peel_to_commit()
322→        .map_err(|e| format!("Failed to resolve default branch: {}", e))?;
323→
324→    // Find merge base
325→    let merge_base_oid = repo
326→        .merge_base(default_commit.id(), branch_commit.id())
327→        .map_err(|e| format!("Failed to find merge base: {}", e))?;
328→    let merge_base_commit = repo
329→        .find_commit(merge_base_oid)
330→        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;
331→
332→    let base_tree = merge_base_commit
333→        .tree()
334→        .map_err(|e| format!("Failed to get base tree: {}", e))?;
335→    let branch_tree = branch_commit
336→        .tree()
337→        .map_err(|e| format!("Failed to get branch tree: {}", e))?;
338→
339→    let diff = repo
340→        .diff_tree_to_tree(Some(&base_tree), Some(&branch_tree), None)
341→        .map_err(|e| format!("Failed to compute branch diff: {}", e))?;
342→
343→    collect_diff_files(&diff)
344→}
