346→#[tauri::command]
347→fn watch_repo(
348→    repo_path: String,
349→    app: tauri::AppHandle,
350→    state: State<'_, Mutex<AppState>>,
351→) -> Result<(), String> {
352→    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;
353→
354→    // Don't double-watch
355→    if app_state.watched_repos.contains(&repo_path) {
356→        return Ok(());
357→    }
358→    app_state.watched_repos.insert(repo_path.clone());
359→
360→    let app_handle = app.clone();
361→    let repo_path_for_closure = repo_path.clone();
362→    watcher::watch_repo(&repo_path, move |event| {
363→        let event_name = match event {
364→            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
365→            watcher::WatchEvent::SessionChanged(_) => "session-changed",
366→            watcher::WatchEvent::ConfigChanged => "config-changed",
367→        };
368→        let _ = app_handle.emit(event_name, serde_json::json!({
369→            "repoPath": repo_path_for_closure,
370→        }));
371→    })?;
372→
373→    Ok(())
374→}
