376→#[cfg_attr(mobile, tauri::mobile_entry_point)]
377→pub fn run() {
378→    tauri::Builder::default()
379→        .plugin(tauri_plugin_opener::init())
380→        .plugin(tauri_plugin_window_state::Builder::default().build())
381→        .manage(Mutex::new(AppState {
382→            pty_manager: pty::PtyManager::new(),
383→            watched_repos: HashSet::new(),
384→        }))
385→        .setup(|app| {
386→            // System tray
387→            use tauri::menu::{MenuBuilder, MenuItemBuilder};
388→            use tauri::tray::TrayIconBuilder;
389→            use tauri::Manager;
390→
391→            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
392→            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
393→            let menu = MenuBuilder::new(app)
394→                .item(&show)
395→                .separator()
396→                .item(&quit)
397→                .build()?;
398→
399→            let _tray = TrayIconBuilder::new()
400→                .tooltip("Entire Desktop")
401→                .menu(&menu)
402→                .on_menu_event(move |app, event| {
403→                    match event.id().as_ref() {
404→                        "show" => {
405→                            if let Some(window) = app.get_webview_window("main") {
406→                                let _ = window.show();
407→                                let _ = window.set_focus();
408→                            }
409→                        }
410→                        "quit" => {
411→                            app.exit(0);
412→                        }
413→                        _ => {}
414→                    }
415→                })
416→                .on_tray_icon_event(|tray, event| {
417→                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
418→                        let app = tray.app_handle();
419→                        if let Some(window) = app.get_webview_window("main") {
420→                            let _ = window.show();
421→                            let _ = window.set_focus();
422→                        }
423→                    }
424→                })
425→                .build(app)?;
426→
427→            Ok(())
428→        })
429→        .invoke_handler(tauri::generate_handler![
430→            list_repos,
431→            list_checkpoints,
432→            get_transcript,
433→            get_checkpoint_diff,
434→            get_branch_diff,
435→            list_sessions,
436→            spawn_agent,
437→            pty_input,
438→            pty_resize,
439→            kill_pty,
440→            list_trails,
441→            watch_repo,
442→        ])
443→        .run(tauri::generate_context!())
444→        .expect("error while running tauri application");
445→}
