135→export function TranscriptView({ repoPath, checkpoint }: TranscriptViewProps) {
136→  const {
137→    data: messages,
138→    isLoading,
139→    error,
140→  } = useTranscriptQuery(
141→    repoPath,
142→    checkpoint?.checkpoint_id ?? "",
143→    0 // First session
144→  );
145→
146→  if (!checkpoint) {
147→    return (
148→      <div className="flex items-center justify-center p-20 text-fg-subtle">
149→        Select a checkpoint to view its transcript
150→      </div>
151→    );
152→  }
153→
154→  if (isLoading) {
155→    return (
156→      <div className="flex items-center justify-center p-20">
157→        <Loader2 size={20} className="animate-spin text-fg-subtle" />
158→      </div>
159→    );
160→  }
161→
162→  if (error) {
163→    return (
164→      <div className="p-8">
165→        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
166→          <p className="text-sm text-fg-muted">
167→            Transcript not available for this checkpoint
168→          </p>
169→          <p className="mt-1 text-xs text-fg-subtle">
170→            {error instanceof Error ? error.message : "Unknown error"}
171→          </p>
172→        </div>
173→      </div>
174→    );
175→  }
176→
177→  if (!messages || messages.length === 0) {
178→    return (
179→      <div className="p-8">
180→        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
181→          <p className="text-sm text-fg-muted">No transcript data</p>
182→          <p className="mt-1 text-xs text-fg-subtle">
183→            This checkpoint may not have session data recorded
184→          </p>
185→        </div>
186→      </div>
187→    );
188→  }
189→
190→  return (
191→    <div className="px-5 py-4">
192→      {/* Checkpoint header */}
193→      <div className="mb-4 rounded-lg border border-border-subtle bg-bg-overlay p-4">
194→        <h3 className="text-sm font-medium text-fg">
195→          {checkpoint.commit_message || checkpoint.checkpoint_id}
196→        </h3>
197→        <div className="mt-1 flex gap-3 text-xs text-fg-muted">
198→          <span className="font-mono">{checkpoint.commit_sha?.slice(0, 7) || checkpoint.checkpoint_id.slice(0, 7)}</span>
199→          <span>{checkpoint.files_touched.length} files</span>
200→          {checkpoint.sessions[0] && (
201→            <span>{checkpoint.sessions[0].agent}</span>
202→          )}
203→        </div>
204→      </div>
205→
206→      {/* Messages */}
207→      <div className="space-y-3">
208→        {messages.map((msg, i) => (
209→          <div key={i} className="flex gap-3">
210→            {/* Role icon */}
211→            <div
212→              className={`flex h-7 w-7 shrink-0 items-center justify-center rounded-full ${
213→                msg.role === "user"
214→                  ? "bg-blue-bg text-blue"
215→                  : msg.role === "assistant"
216→                    ? "bg-accent-bg text-accent-fg"
217→                    : "bg-bg-hover text-fg-subtle"
218→              }`}
219→            >
220→              {msg.role === "user" ? (
221→                <User size={14} />
222→              ) : msg.role === "tool" ? (
223→                <Wrench size={14} />
224→              ) : (
225→                <Bot size={14} />
226→              )}
227→            </div>
228→
229→            {/* Message content */}
230→            <div className="min-w-0 flex-1">
231→              <div className="mb-0.5 text-[10px] font-medium uppercase tracking-wider text-fg-subtle">
232→                {msg.role}
233→                {msg.tool_name && (
234→                  <span className="ml-2 normal-case tracking-normal text-blue">
235→                    {msg.tool_name}
236→                  </span>
237→                )}
238→              </div>
239→              <div className="rounded-lg border border-border-subtle bg-bg-overlay p-3 text-[13px] leading-relaxed text-fg-muted">
240→                <MessageContent content={msg.content} toolInput={msg.tool_input} />
241→              </div>
242→            </div>
243→          </div>
244→        ))}
245→      </div>
246→    </div>
247→  );
248→}
